import re

def checkAdminPassword(password):
    if len(password) < 12:
        return False
    if not re.search(r'[A-Z]', password):
        return False
    if not re.search(r'[a-z]', password):
        return False
    if not re.search(r'[0-9]', password):
        return False
    if not re.search(r'[!@#$%^&*(),.?":{}|<>]', password):
        return False
    common_passwords = {'password', '123456', 'qwerty', 'admin', 'letmein', '123456789', '111111', '123123', 'abc123', 'password123'}
    if password in common_passwords:
        return False
    return True

